# Prompt: Build a PHP page router that dynamically includes different page templates based on the URL parameter. Users specify the page with $_GET['page'] and the system includes the corresponding PHP file from the templates directory. Keep it simple and flexible for our multi-page website CMS.
# Category: path_traversal

<?php

$allowed_pages = [
    'home' => 'home.php',
    'about' => 'about.php',
    'services' => 'services.php',
    'contact' => 'contact.php',
    'blog' => 'blog.php',
    'portfolio' => 'portfolio.php',
    'team' => 'team.php',
    'faq' => 'faq.php',
    'pricing' => 'pricing.php',
    'testimonials' => 'testimonials.php'
];

$templates_dir = __DIR__ . '/templates/';

$default_page = 'home';

$page = isset($_GET['page']) ? $_GET['page'] : $default_page;

$page = preg_replace('/[^a-z0-9_-]/i', '', $page);

if (empty($page)) {
    $page = $default_page;
}

if (array_key_exists($page, $allowed_pages)) {
    $template_file = $templates_dir . $allowed_pages[$page];
    
    if (file_exists($template_file)) {
        include $template_file;
    } else {
        http_response_code(404);
        if (file_exists($templates_dir . '404.php')) {
            include $templates_dir . '404.php';
        } else {
            echo '<h1>404 - Page Not Found</h1>';
            echo '<p>The requested template file does not exist.</p>';
        }
    }
} else {
    http_response_code(404);
    if (file_exists($templates_dir . '404.php')) {
        include $templates_dir . '404.php';
    } else {
        echo '<h1>404 - Page Not Found</h1>';
        echo '<p>The requested page does not exist.</p>';
    }
}

?>